example.code:
// Key structure: K8s agent, parallel tests, security scan, staged deploy
pipeline {
    agent {
        kubernetes {
            yaml '''
                spec:
                  containers:
                  - name: node
                    image: node:20-alpine
                    command: [cat]
                    tty: true
                  - name: docker
                    image: docker:24-dind
                    securityContext:
                      privileged: true
            '''
        }
    }
    environment {
        VERSION = "${env.BUILD_NUMBER}-${env.GIT_COMMIT.take(7)}"
    }
    stages {
        stage('Test') {
            parallel {
                stage('Unit') { steps { container('node') { sh 'npm run test:unit' } } }
                stage('Security') { steps { container('node') { sh 'npm audit --audit-level=high' } } }
            }
        }
        stage('Build') {
            steps { container('docker') { sh 'docker build -t ${DOCKER_REGISTRY}/${APP_NAME}:${VERSION} .' } }
        }
        stage('Deploy Staging') {
            when { branch 'main' }
            steps { /* kubectl set image + rollout status */ }
        }
        stage('Deploy Production') {
            when { branch 'main' }
            input { message "Deploy to production?"; submitter "admin,deployers" }
            steps { /* kubectl production deploy */ }
        }
    }
    post {
        always { cleanWs() }
        failure { slackSend(color: 'danger', message: "FAILED: ${env.JOB_NAME}") }
    }
}

// Detect changed services and build only those
node('docker') {
    stage('Detect Changes') {
        checkout scm
        def changedFiles = sh(script: "git diff --name-only HEAD~1", returnStdout: true).trim().split('\n')
        services = ['api', 'web', 'worker'].findAll { service ->
            changedFiles.any { it.startsWith("services/${service}/") }
        }
        if (services.isEmpty()) { currentBuild.result = 'SUCCESS'; return }
    }
    stage('Build Changed Services') {
        def parallelStages = [:]
        services.each { service ->
            parallelStages["Build ${service}"] = {
                node('docker') {
                    checkout scm
                    dir("services/${service}") { sh "docker build -t ${service}:${BUILD_NUMBER} ." }
                }
            }
        }
        parallel parallelStages
    }
}

stage('Build Matrix') {
    matrix {
        axes {
            axis { name 'NODE_VERSION'; values '18', '20', '22' }
            axis { name 'OS'; values 'linux', 'macos' }
        }
        stages {
            stage('Build') {
                agent { label "${OS}" }
                steps { sh "nvm use ${NODE_VERSION} && npm ci && npm test" }
            }
        }
    }
}
